import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent) {
        if (intent.action == Intent.ACTION_VIEW && intent.data != null) {
            val uri = intent.data
            when {
                uri?.host == "profile" -> {
                    val id = uri.pathSegments.getOrNull(1)?.toIntOrNull()
                    if (id != null) {
                        navigateToProfileActivity(id)
                    }
                }
                uri?.host == "payment" && uri?.pathSegments.contains("confirm") -> {
                    navigateToPaymentConfirmActivity()
                }
                else -> {
                    // Handle other deep links or show an error
                }
            }
        }
    }

    private fun navigateToProfileActivity(userId: Int) {
        val intent = Intent(this, ProfileActivity::class.java)
        intent.putExtra("user_id", userId)
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmActivity() {
        val intent = Intent(this, PaymentConfirmActivity::class.java)
        startActivity(intent)
    }
}